scripts.script:
// Facet (#13): register named themes ONCE (palette + design tokens + mode).
// Any chart can then reference one by name via theme:{ name }, and switching
// themes is a single updateOptions call.
ApexCharts.registerTheme('sunset', {
  palette: ['#ff6b6b', '#f06595', '#cc5de8', '#845ef7', '#ff922b'],
  tokens: { fore: '#5c3d2e', grid: '#f3d9c4', surface: '#fff8f2' },
})
ApexCharts.registerTheme('ocean', {
  palette: ['#0ca678', '#1098ad', '#1971c2', '#3b5bdb', '#0b7285'],
  tokens: { fore: '#0b3d4d', grid: '#c5e4ec', surface: '#f2fbfd' },
})
ApexCharts.registerTheme('slate', {
  mode: 'dark',
  palette: ['#94a3b8', '#38bdf8', '#a78bfa', '#f472b6', '#fbbf24'],
  tokens: { fore: '#e2e8f0', grid: '#334155', surface: '#0f172a' },
})

chart.options:
chart: {
  height: 400,
  type: 'bar',
  fontFamily: 'sans-serif',
  animations: { enabled: true },
  toolbar: { show: false },
},
theme: {
  name: 'sunset',
},
plotOptions: { bar: { columnWidth: '55%', borderRadius: 4, distributed: true } },
dataLabels: { enabled: false },
legend: { show: false },
title: {
  text: 'Revenue by channel',
  align: 'left',
},
subtitle: {
  text: 'Palette and chrome come from a registered brand theme',
  align: 'left',
},
xaxis: {
  type: 'category',
  categories: ['Direct', 'Search', 'Social', 'Email', 'Referral'],
},
